        self.target_number = random.randint(self.lower_bound, self.upper_bound)
        self.guesses_taken = 0

    def make_guess(self, guess):
        self.guesses_taken += 1
        if guess < self.target_number:
            return "Too low!"
        elif guess > self.target_number:
            return "Too high!"
        else:
            return "Correct!"

    def is_game_over(self, guess):
        return guess == self.target_number


def main():
    print("Welcome to the Number Guessing Game!")
    lower_bound = 1
    upper_bound = 100
    game = NumberGuessingGame(lower_bound, upper_bound)

    while True:
        try:
            guess = int(input(f"Guess a number between {lower_bound} and {upper_bound}: "))
            if guess < lower_bound or guess > upper_bound:
                print(f"Please guess a number within the range of {lower_bound} to {upper_bound}.")
                continue

            feedback = game.make_guess(guess)
            print(feedback)

            if game.is_game_over(guess):
                print(f"You guessed the number {game.target_number} in {game.guesses_taken} tries!")
                play_again = input("Do you want to play again? (yes/no): ").strip().lower()
                if play_again == 'yes':
                    game.reset_game()
                else:
                    print("Thanks for playing!")
                    break

        except ValueError:
            print("Please enter a valid number.")


if __name__ == "__main__":
