#!/usr/bin/env python3
import os

def clear_screen():
    os.system('cls' if os.name == 'nt' else 'clear')

def print_board(board):
    print()
    print(f" {board[0]} | {board[1]} | {board[2]} ")
    print("---+---+---")
    print(f" {board[3]} | {board[4]} | {board[5]} ")
    print("---+---+---")
    print(f" {board[6]} | {board[7]} | {board[8]} ")
    print()

def has_winner(board, mark):
    wins = [
        (0, 1, 2),  # Top row
        (3, 4, 5),  # Middle row
        (6, 7, 8),  # Bottom row
        (0, 3, 6),  # Left column
        (1, 4, 7),  # Middle column
        (2, 5, 8),  # Right column
        (0, 4, 8),  # Diagonal
        (2, 4, 6)   # Diagonal
    ]
    for a, b, c in wins:
        if board[a] == board[b] == board[c] == mark:
            return True
    return False

def is_board_full(board):
    return all(cell in ['X', 'O'] for cell in board)

def get_player_move(board, player):
    while True:
        try:
            move = int(input(f"Player {player} turn. Enter a cell number (1-9): "))
            if move < 1 or move > 9:
                print("Invalid cell number. Choose a number between 1 and 9.")
                continue
            if board[move-1] in ['X', 'O']:
                print("That cell is already taken. Choose another one.")
                continue
            return move-1
        except ValueError:
            print("Please enter a valid integer.")

def play_game():
    board = [str(i+1) for i in range(9)]
    current_player = "X"

    while True:
        clear_screen()
        print_board(board)
        move = get_player_move(board, current_player)
        board[move] = current_player

        if has_winner(board, current_player):
            clear_screen()
            print_board(board)
            print(f"Player {current_player} wins!")
            break

        if is_board_full(board):
            clear_screen()
            print_board(board)
            print("It's a tie!")
            break

        current_player = "O" if current_player == "X" else "X"

def main():
    while True:
        play_game()
        replay = input("Play again? (y/n): ").lower()
        if replay != 'y':
            print("Thanks for playing!")
            break

if __name__ == "__main__":
    main()
